import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classic() {
        // Remove [1,3]; remaining [1,2],[2,3],[3,4] share only endpoints
        assertEquals(1, new Solution().eraseOverlapIntervals(new int[][]{{1,2},{2,3},{3,4},{1,3}}));
    }

    @Test
    void allIdentical() {
        // Three copies of [1,2]: keep one, remove two
        assertEquals(2, new Solution().eraseOverlapIntervals(new int[][]{{1,2},{1,2},{1,2}}));
    }

    @Test
    void endpointTouchDoesNotOverlap() {
        // [1,2] and [2,3] share endpoint 2 — NOT an overlap, remove 0
        assertEquals(0, new Solution().eraseOverlapIntervals(new int[][]{{1,2},{2,3}}));
    }

    @Test
    void noOverlapAtAll() {
        // Completely disjoint — nothing to remove
        assertEquals(0, new Solution().eraseOverlapIntervals(new int[][]{{1,2},{3,4},{5,6}}));
    }

    @Test
    void allOverlapOneKept() {
        // All intervals span [1,10]; keep 1, remove 3
        assertEquals(3, new Solution().eraseOverlapIntervals(new int[][]{{1,10},{1,5},{2,8},{3,7}}));
    }

    @Test
    void singleInterval() {
        assertEquals(0, new Solution().eraseOverlapIntervals(new int[][]{{3,9}}));
    }

    @Test
    void emptyInput() {
        assertEquals(0, new Solution().eraseOverlapIntervals(new int[][]{}));
    }
}
